const items = $input.all()[0].json;
const clients = $input.all()[1].json;

const matches = clients.map(client => {
  const matchedItems = items.filter(item => {
    const sizeMatch = item.sizes.includes(client.preferences.size);
    const styleMatch = client.preferences.styles.some(s => item.tags.includes(s));
    const brandMatch = client.preferences.brands.includes(item.brand);
    const priceMatch = item.price >= client.preferences.priceRange[0] && item.price <= client.preferences.priceRange[1];
    return sizeMatch && styleMatch && brandMatch && priceMatch;
  });

  return { client, matchedItems };
}).filter(m => m.matchedItems.length > 0);

return { matches, totalMatches: matches.length };

const matches = $input.first().json.matches;

// Round-robin assignment
const associates = ['Sarah', 'Michael', 'Emma', 'David'];

const assigned = matches.map((m, i) => ({
  ...m,
  assignedAssociate: associates[i % associates.length],
  priority: m.client.tier === 'Platinum' ? 'HIGH' : m.client.tier === 'Gold' ? 'MEDIUM' : 'NORMAL'
}));

return { assigned };

